function renderMenu(filter) {
  const grid = document.getElementById('menu-grid');
  const items = filter === 'all' ? MENU_ITEMS : MENU_ITEMS.filter(i => i.category === filter);
  grid.innerHTML = items.map(item => `
    <div class="menu-card reveal" data-id="${item.id}" onclick="openProductModal(${item.id})">
      <div class="menu-card-img">
        ${item.bestSeller ? '<span class="best-seller-tag">⭐ Best Seller</span>' : ''}
        ${item.img
          ? `<img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:cover;display:block;">`
          : `<span style="font-size:5rem">${item.emoji}</span>`
        }
        <div class="menu-overlay">
          <div class="overlay-ingredients">${item.ingredients}</div>
          <button class="quick-view-btn" onclick="event.stopPropagation(); openProductModal(${item.id})">Quick View</button>
        </div>
      </div>
      <div class="menu-card-body">
        <h3 class="menu-card-name">${item.name}</h3>
        <p class="menu-card-desc">${item.desc}</p>
        <div class="menu-card-footer">
          <span class="menu-price">UGX ${item.price.toLocaleString()}</span>
          <div class="menu-actions">
            <button class="heart-btn ${favorites.includes(item.id) ? 'active' : ''}" onclick="event.stopPropagation(); toggleFavorite(${item.id}, this)">
              ${favorites.includes(item.id) ? '❤️' : '🤍'}
            </button>
            <button class="add-cart-btn" onclick="event.stopPropagation(); quickAddToCart(${item.id})">
              + Add
            </button>
          </div>
        </div>
      </div>
    </div>
  `).join('');
  grid.querySelectorAll('.reveal').forEach(el => revealObserver.observe(el));
}

