// ============================================================
// FAVORITES
// ============================================================
function toggleFavorite(id, btn) {
  const idx = favorites.indexOf(id);
  if (idx > -1) {
    favorites.splice(idx, 1);
    btn.classList.remove('active');
    btn.textContent = '🤍';
  } else {
    favorites.push(id);
    btn.classList.add('active');
    btn.textContent = '❤️';
  }
  localStorage.setItem('yummy_favorites', JSON.stringify(favorites));
}

// ============================================================
// CART
// ============================================================
function saveCart() {
  localStorage.setItem('yummy_cart', JSON.stringify(cart));
}

function updateCartUI() {
  const count = cart.reduce((s, i) => s + i.qty, 0);
  document.getElementById('cart-count').textContent = count;
  const total = cart.reduce((s, i) => s + i.price * i.qty, 0);
  document.getElementById('cart-total-price').textContent = 'UGX ' + total.toLocaleString();
  const container = document.getElementById('cart-items');
  if (!cart.length) {
    container.innerHTML = '<div class="cart-empty">Your cart is empty.<br>Add something delicious! 🍰</div>';
    return;
  }
  container.innerHTML = cart.map(item => `
    <div class="cart-item">
      <span class="cart-item-emoji">${item.emoji}</span>
      <div class="cart-item-info">
        <div class="cart-item-name">${item.name}</div>
        <div class="cart-item-price">UGX ${(item.price * item.qty).toLocaleString()}</div>
      </div>
      <div class="qty-controls">
        <button class="qty-btn" onclick="changeQty(${item.id}, -1)">−</button>
        <span class="qty-val">${item.qty}</span>
        <button class="qty-btn" onclick="changeQty(${item.id}, 1)">+</button>
      </div>
    </div>
  `).join('');
}

function addToCart(item, qty = 1) {
  const existing = cart.find(c => c.id === item.id);
  if (existing) { existing.qty += qty; }
  else { cart.push({ ...item, qty }); }
  saveCart();
  updateCartUI();
  openCart();
}

function quickAddToCart(id) {
  const item = MENU_ITEMS.find(i => i.id === id);
  addToCart(item);
}

function changeQty(id, delta) {
  const item = cart.find(i => i.id === id);
  if (!item) return;
  item.qty += delta;
  if (item.qty <= 0) cart.splice(cart.indexOf(item), 1);
  saveCart();
  updateCartUI();
}

function openCart() {
  document.getElementById('cart-sidebar').classList.add('open');
  document.getElementById('cart-overlay').classList.add('active');
}
function closeCart() {
  document.getElementById('cart-sidebar').classList.remove('open');
  document.getElementById('cart-overlay').classList.remove('active');
}

function checkoutViaWhatsApp() {
  if (cart.length === 0) return;
  const orderLines = cart.map(i => `${i.name} x${i.qty} - UGX ${(i.price * i.qty).toLocaleString()}`).join('%0A');
  const total = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const msg = `Hello Yummy! I'd like to order:%0A${orderLines}%0ATotal: UGX ${total.toLocaleString()}`;
  window.open(`https://wa.me/256708526671?text=${msg}`, '_blank');
  closeCart();
}

