function openProductModal(id) {
  const item = MENU_ITEMS.find(i => i.id === id);
  modalItem = item;
  modalQty = 1;
  document.getElementById('modal-emoji').textContent = item.emoji;
  document.getElementById('modal-title').textContent = item.name;
  document.getElementById('modal-price').textContent = 'UGX ' + item.price.toLocaleString();
  document.getElementById('modal-desc').textContent = item.desc + ' · ' + item.ingredients;
  document.getElementById('modal-qty').textContent = 1;
  document.getElementById('product-modal').classList.add('open');
}

function changeModalQty(delta) {
  modalQty = Math.max(1, modalQty + delta);
  document.getElementById('modal-qty').textContent = modalQty;
}

function addModalToCart() {
  if (!modalItem) return;
  addToCart(modalItem, modalQty);
  closeModal('product-modal');
}

function closeModal(id) {
  document.getElementById(id).classList.remove('open');
}

