// Drag scroll
const wrap = document.getElementById('gelato-track-wrap');
let isDragging = false, startX, scrollLeft;
wrap.addEventListener('mousedown', e => {
  isDragging = true; startX = e.pageX - wrap.offsetLeft; scrollLeft = wrap.scrollLeft;
  wrap.classList.add('dragging');
});
wrap.addEventListener('mouseleave', () => { isDragging = false; wrap.classList.remove('dragging'); });
wrap.addEventListener('mouseup', () => { isDragging = false; wrap.classList.remove('dragging'); });
wrap.addEventListener('mousemove', e => {
  if (!isDragging) return;
  e.preventDefault();
  const x = e.pageX - wrap.offsetLeft;
  const walk = (x - startX) * 2;
  wrap.scrollLeft = scrollLeft - walk;
});

// ============================================================
// ANIMATED COUNTERS
// ============================================================
const counterObserver = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if (e.isIntersecting) {
      const el = e.target;
      const target = parseInt(el.dataset.target);
      const duration = 1800;
      const step = target / (duration / 16);
      let current = 0;
      const timer = setInterval(() => {
        current = Math.min(current + step, target);
        el.textContent = (current >= target ? target : Math.floor(current)) + (target >= 1000 ? '+' : target >= 20 ? '+' : '');
        if (current >= target) clearInterval(timer);
      }, 16);
      counterObserver.unobserve(el);
    }
  });
}, { threshold: 0.5 });
document.querySelectorAll('[data-target]').forEach(el => counterObserver.observe(el));

