// DESSERT PICKER
// ============================================================
function spinDessert() {
  const btn = document.getElementById('spin-btn');
  btn.classList.add('spinning');
  btn.textContent = '🎲 Spinning...';
  let count = 0;
  const interval = setInterval(() => {
    const random = DESSERTS[Math.floor(Math.random() * DESSERTS.length)];
    document.getElementById('dessert-result').innerHTML = `
      <span class="dessert-result-emoji">${random.emoji}</span>
      <p class="dessert-result-name">${random.name}</p>
      <p class="dessert-result-desc">${random.desc}</p>
    `;
    count++;
    if (count > 10) {
      clearInterval(interval);
      btn.classList.remove('spinning');
      btn.textContent = '🎲 Spin Again!';
    }
  }, 120);
}

// ============================================================
// CONFETTI
// ============================================================
function confettiBurst() {
  const colors = ['#D4A843', '#FFE082', '#FF6B8A', '#A8D5A2', '#F5E6C8', '#6B3A1F'];
  for (let i = 0; i < 60; i++) {
    const p = document.createElement('div');
    p.className = 'confetti-piece';
    p.style.left = Math.random() * 100 + 'vw';
    p.style.background = colors[Math.floor(Math.random() * colors.length)];
    p.style.width = (8 + Math.random() * 8) + 'px';
    p.style.height = (10 + Math.random() * 10) + 'px';
    p.style.setProperty('--drift', (Math.random() * 200 - 100) + 'px');
    p.style.animationDuration = (2 + Math.random() * 2) + 's';
    p.style.animationDelay = Math.random() * 0.5 + 's';
    p.style.borderRadius = Math.random() > 0.5 ? '50%' : '2px';
    document.body.appendChild(p);
    setTimeout(() => p.remove(), 4000);
  }
}

